"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import {
  Alert,
  Box,
  Button,
  Container,
  Paper,
  Stack,
  Tab,
  Tabs,
  TextField,
  Typography,
} from "@mui/material";
import { useAuth } from "@/lib/auth/authContext";

export default function AuthPage() {
  const { login, register } = useAuth();
  const router = useRouter();
  const [isLogin, setIsLogin] = useState(true);
  const [fullName, setFullName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const resetForm = () => {
    setFullName("");
    setEmail("");
    setPassword("");
    setError("");
  };
  
const handleTabChange = (_: React.SyntheticEvent, value: number) => {
    setIsLogin(value === 0);
    resetForm();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);
    try {
      if (isLogin) {
        await login(email, password);
      } else {
        await register(fullName, email, password);
      }
      router.push("/projects");
    } catch {
      setError(
        isLogin
          ? "Invalid email or password."
          : "Something went wrong. Please try again."
      );
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Box className="min-h-screen flex items-center justify-center bg-indigo-50 dark:bg-indigo-950">
      <Container maxWidth="sm">
        <Paper className="overflow-hidden rounded-2xl shadow-xl dark:bg-indigo-900" elevation={0}>
          <Tabs
            value={isLogin ? 0 : 1}
            onChange={handleTabChange}
            variant="fullWidth"
            className="bg-indigo-100 dark:bg-indigo-800"
          >
            <Tab
              label="Sign in"
              className="font-semibold text-indigo-700 dark:text-indigo-200"
            />
            <Tab
              label="Create account"
              className="font-semibold text-indigo-700 dark:text-indigo-200"
            />
          </Tabs>

          <Box
            component="form"
            onSubmit={handleSubmit}
            className="p-8 flex flex-col gap-5"
          >
            <Stack spacing={0.5}>
              <Typography
                variant="h5"
                className="font-bold text-indigo-900 dark:text-indigo-100"
              >
                {isLogin ? "Welcome back" : "Get started"}
              </Typography>
              <Typography
                variant="body2"
                className="text-indigo-500 dark:text-indigo-300"
              >
                {isLogin
                  ? "Sign in to your TaskFlow account"
                  : "Create your free TaskFlow account"}
              </Typography>
            </Stack>

            {error && <Alert severity="error">{error}</Alert>}

            {!isLogin && (
              <TextField
                label="Full Name"
                value={fullName}
                onChange={(e) => setFullName(e.target.value)}
                required
                fullWidth
                autoComplete="name"
              />
            )}

            <TextField
              label="Email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              fullWidth
              autoComplete="email"
            />

            <TextField
              label="Password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              fullWidth
              autoComplete={isLogin ? "current-password" : "new-password"}
            />

            <Button
              type="submit"
              variant="contained"
              disabled={isLoading}
              fullWidth
              className="bg-indigo-600 hover:bg-indigo-700 dark:bg-indigo-500 dark:hover:bg-indigo-400 text-white font-semibold py-3 rounded-xl normal-case"
            >
              {isLoading
                ? isLogin
                  ? "Signing in..."
                  : "Creating account..."
                : isLogin
                  ? "Sign in"
                  : "Create account"}
            </Button>
          </Box>
        </Paper>
      </Container>
    </Box>
  );
}
